windowclass.script:
			local sFoeKillBonusWatchXPPath = "";
			local sFoeKillBonusWatchCharPath = "";

			function onInit()
				if super and super.onInit then
					super.onInit();
				end

				if User.isHost() then
					--[[ GM view, include GM notes ]]
					totalframe.setVisible(true);
					mutliplier.setVisible(true);
					adventuretotal.setVisible(true);
					totallabel.setVisible(true);
					gmlabel.setVisible(true);
					gmexframe.setVisible(true);
					ideaslabel.setVisible(true);
					ideaxp.setVisible(true);
					trvllabel.setVisible(true);
					trvlxp.setVisible(true);
					trvl2label.setVisible(true);
					trvl2xp.setVisible(true);
					manuevertotal.setVisible(true);
					manuevertotallabel.setVisible(true);
					combattotal.setVisible(true);
					combattotallabel.setVisible(true);
					spelltotal.setVisible(true);
					spelltotallabel.setVisible(true);
					totaltotal.setVisible(true);
					totaltotallabel.setVisible(true);
					sessiontotal.setVisible(true);
					sessiontotallabel.setVisible(true);
					combatkills.setVisible(true);
					combatkillslabel.setVisible(true);
					foekillbonuscombo.setVisible(true);
					multiplierlabel.setVisible(true);
					adventuretotallabel.setVisible(true);
				else
					--[[ Player view, exclude GM notes ]]
					totalframe.setVisible(true);
					mutliplier.setVisible(false);
					adventuretotal.setVisible(false);
					totallabel.setVisible(false);
					gmlabel.setVisible(false);
					gmexframe.setVisible(true);
					ideaslabel.setVisible(true);
					ideaxp.setVisible(true);
					trvllabel.setVisible(true);
					trvlxp.setVisible(true);
					trvl2label.setVisible(true);
					trvl2xp.setVisible(true);
					manuevertotal.setVisible(false);
					manuevertotallabel.setVisible(false);
					combattotal.setVisible(false);
					combattotallabel.setVisible(false);
					spelltotal.setVisible(false);
					spelltotallabel.setVisible(false);
					totaltotal.setVisible(false);
					totaltotallabel.setVisible(false);
					sessiontotal.setVisible(true);
					sessiontotallabel.setVisible(true);
					combatkills.setVisible(false);
					combatkillslabel.setVisible(false);
					foekillbonuscombo.setVisible(true);
					multiplierlabel.setVisible(false);
					adventuretotallabel.setVisible(false);
				end

				registerFoeKillBonusHandlers();
				refresh();
			end

			function onClose()
				unregisterFoeKillBonusHandlers();
			end

			function isHostOrOwner()
				if User.isHost() then
					return true;
				end

				local nodeXP = getDatabaseNode();
				if not nodeXP then
					return false;
				end

				local nodeChar = nodeXP.getParent();
				if not nodeChar then
					return false;
				end

				if nodeChar.isReadOnly and nodeChar.isReadOnly() then
					return false;
				end

				if nodeChar.isOwner then
					return nodeChar.isOwner();
				end

				return false;
			end

			function spellcalc(spelllvl)
				local lvl;
				local calctotal;

				lvl = level.getValue();
				calctotal = math.floor(100-((lvl-spelllvl)*10));
					if calctotal  > 200 then
						calctotal = 200;
					end
				return calctotal;
			end

			function CalcLevelFromXP(nTotalXP)
				local nLevel = 0;
				local aLevelXP = {10000, 20000, 30000, 40000, 50000, 70000, 90000, 110000, 130000, 150000,
								175000, 200000, 225000, 250000, 275000, 300000, 325000, 350000, 375000, 400000,
								425000, 450000, 475000, 500000};

				for i = 1, #aLevelXP do
					if nTotalXP >= aLevelXP[i] then
						nLevel = i;
					else
						break;
					end
				end

				return nLevel;
			end


function refresh()
    local mantot;
    local sesstot;
    mantot = (routine.getValue() * 0) + (easy.getValue() * 5) + (light.getValue() * 10) + (medium.getValue() * 50) + (hard.getValue() * 100) +
             (veryhard.getValue() * 150) + (extremelyhard.getValue() * 200) + (sheerfolly.getValue() * 300) + (absurd.getValue() * 500);
    manuevertotal.setValue(mantot);

    local comtot;

	local combatMultiplier = combatxpdesc.getValue() or 1;
	local foeValue = foekillbase.getValue() or 0;
	if combatkills.getValue() ~= foeValue then
		combatkills.setValue(foeValue);
	end

    local critValue = crit() * combatMultiplier;

    comtot = hitsgiven.getValue() + hitstaken.getValue() + critValue + foeValue; -- Usa o valor atualizado de combatkills
    combattotal.setValue(comtot);

    local spelltot;
    spelltot = spellcalc(1) * spellone.getValue() + spellcalc(2) * spelltwo.getValue() + spellcalc(3) * spellthree.getValue() +
               spellcalc(4) * spellfour.getValue() + spellcalc(5) * spellfive.getValue() + spellcalc(6) * spellsix.getValue() +
               spellcalc(7) * spellseven.getValue() + spellcalc(8) * spelleight.getValue() + spellcalc(9) * spellnine.getValue() +
               spellcalc(10) * spellten.getValue() + 200 * spelleleven.getValue();
    spelltotal.setValue(spelltot);

    sesstot = (mantot + comtot + spelltot + ideaxp.getValue() + trvlxp.getValue() + trvl2xp.getValue() + adventuretotal.getValue()) *
              mutliplier.getValue();
    sessiontotal.setValue(sesstot);

	-- Atualizar o nÃ­vel do personagem baseado no XP total
	local nTotalXP = xp.getValue();
	local nNewLevel = CalcLevelFromXP(nTotalXP);
	level.setValue(nNewLevel);

	-- Atualizar o nÃ­vel do personagem no banco de dados para que as skills recebam o bÃ´nus correto
	local nodeChar = getDatabaseNode().getParent();
	if nodeChar and isHostOrOwner() then
		DB.setValue(nodeChar, "level", "number", nNewLevel);
	end

	refreshFoeKillBonusCombo();
end

			function hasFoeKillBonusEntries(nodeData)
				if not nodeData then
					return false;
				end

				for _, _ in pairs(DB.getChildren(nodeData, "foekillbonuslist")) do
					return true;
				end

				return false;
			end

			function getFoeKillBonusStorageNode()
				local nodeXP = getDatabaseNode();
				if not nodeXP then
					return nil;
				end

				if hasFoeKillBonusEntries(nodeXP) then
					return nodeXP;
				end

				local nodeParent = nodeXP.getParent and nodeXP.getParent();
				if nodeParent and hasFoeKillBonusEntries(nodeParent) then
					return nodeParent;
				end

				if DB.getValue(nodeXP, "foekill", nil) ~= nil then
					return nodeXP;
				end

				if nodeParent then
					return nodeParent;
				end

				return nodeXP;
			end

			function onFoeKillBonusListChanged()
				refreshFoeKillBonusCombo();
			end

			function unregisterFoeKillBonusHandlers()
				if sFoeKillBonusWatchXPPath ~= "" then
					DB.removeHandler(sFoeKillBonusWatchXPPath .. ".foekillbonuslist", "onChildAdded", onFoeKillBonusListChanged);
					DB.removeHandler(sFoeKillBonusWatchXPPath .. ".foekillbonuslist", "onChildDeleted", onFoeKillBonusListChanged);
					DB.removeHandler(sFoeKillBonusWatchXPPath .. ".foekillbonuslist.*", "onChildUpdate", onFoeKillBonusListChanged);
					sFoeKillBonusWatchXPPath = "";
				end

				if sFoeKillBonusWatchCharPath ~= "" then
					DB.removeHandler(sFoeKillBonusWatchCharPath .. ".foekillbonuslist", "onChildAdded", onFoeKillBonusListChanged);
					DB.removeHandler(sFoeKillBonusWatchCharPath .. ".foekillbonuslist", "onChildDeleted", onFoeKillBonusListChanged);
					DB.removeHandler(sFoeKillBonusWatchCharPath .. ".foekillbonuslist.*", "onChildUpdate", onFoeKillBonusListChanged);
					sFoeKillBonusWatchCharPath = "";
				end
			end

			function registerFoeKillBonusHandlers()
				unregisterFoeKillBonusHandlers();

				local nodeXP = getDatabaseNode();
				if not nodeXP then
					return;
				end

				sFoeKillBonusWatchXPPath = DB.getPath(nodeXP) or "";
				if sFoeKillBonusWatchXPPath ~= "" then
					DB.addHandler(sFoeKillBonusWatchXPPath .. ".foekillbonuslist", "onChildAdded", onFoeKillBonusListChanged);
					DB.addHandler(sFoeKillBonusWatchXPPath .. ".foekillbonuslist", "onChildDeleted", onFoeKillBonusListChanged);
					DB.addHandler(sFoeKillBonusWatchXPPath .. ".foekillbonuslist.*", "onChildUpdate", onFoeKillBonusListChanged);
				end

				local nodeChar = nodeXP.getParent and nodeXP.getParent();
				if nodeChar then
					sFoeKillBonusWatchCharPath = DB.getPath(nodeChar) or "";
					if sFoeKillBonusWatchCharPath ~= "" and sFoeKillBonusWatchCharPath ~= sFoeKillBonusWatchXPPath then
						DB.addHandler(sFoeKillBonusWatchCharPath .. ".foekillbonuslist", "onChildAdded", onFoeKillBonusListChanged);
						DB.addHandler(sFoeKillBonusWatchCharPath .. ".foekillbonuslist", "onChildDeleted", onFoeKillBonusListChanged);
						DB.addHandler(sFoeKillBonusWatchCharPath .. ".foekillbonuslist.*", "onChildUpdate", onFoeKillBonusListChanged);
					end
				end
			end

			function refreshFoeKillBonusCombo()
				if not foekillbonuscombo then
					return;
				end

				foekillbonuscombo.clear();

				local aEntries = {};
				local function addEntriesFromNode(nodeStorage)
					if not nodeStorage then
						return;
					end

					for _, nodeEntry in pairs(DB.getChildren(nodeStorage, "foekillbonuslist")) do
						local sText = DB.getValue(nodeEntry, "text", "");
						if sText == "" then
							local nBonus = tonumber(DB.getValue(nodeEntry, "bonus", 0)) or 0;
							local sFoe = DB.getValue(nodeEntry, "foe", "Unknown");
							sText = string.format("%s - (XP + %d)", sFoe, nBonus);
						end

						if sText ~= "" then
							table.insert(aEntries, sText);
						end
					end
				end

				local nodeXP = getDatabaseNode();
				local nodeChar = nil;
				if nodeXP and nodeXP.getParent then
					nodeChar = nodeXP.getParent();
				end

				addEntriesFromNode(nodeXP);
				if nodeChar and nodeChar ~= nodeXP then
					addEntriesFromNode(nodeChar);
				end

				local function getFoeKillSortKey(sEntry)
					sEntry = tostring(sEntry or "");
					sEntry = sEntry:gsub("^%s*%d+%s*%-%s*", "");
					return sEntry:lower();
				end

				table.sort(aEntries, function(a, b)
					return getFoeKillSortKey(a) < getFoeKillSortKey(b);
				end);
				for _, sEntry in ipairs(aEntries) do
					foekillbonuscombo.add(sEntry, sEntry);
				end

				if #aEntries > 0 then
					local sCurrent = foekillbonuscombo.getValue() or "";
					if sCurrent == "" or not foekillbonuscombo.hasValue(sCurrent) then
						foekillbonuscombo.setValue(aEntries[#aEntries]);
					end
				else
					foekillbonuscombo.setValue("");
				end
			end

			function clearFoeKillBonusEntries()
				local nodeXP = getDatabaseNode();
				local nodeChar = nil;
				if nodeXP and nodeXP.getParent then
					nodeChar = nodeXP.getParent();
				end

				if nodeXP then
					DB.deleteChildren(nodeXP, "foekillbonuslist");
				end

				if nodeChar and nodeChar ~= nodeXP then
					DB.deleteChildren(nodeChar, "foekillbonuslist");
				end
			end

			function addFoeKillBonusEntryFromShortcut(sClass, sRecord)
				if type(sClass) ~= "string" or type(sRecord) ~= "string" or sRecord == "" then
					return false;
				end

				if not StringManager.contains({ "npc", "charsheet", "reference_npc" }, sClass) then
					return false;
				end

				local nodeRecord = DB.findNode(sRecord);
				if not nodeRecord then
					return false;
				end

				local nodeXP = getDatabaseNode();
				if not nodeXP then
					return false;
				end

				local nodeList = DB.createChild(nodeXP, "foekillbonuslist");
				if not nodeList then
					return false;
				end

				local nOrder = 1;
				for _, _ in pairs(DB.getChildren(nodeList)) do
					nOrder = nOrder + 1;
				end

				local sFoeName = DB.getValue(nodeRecord, "name", "Unknown");
				if sFoeName == "" then
					sFoeName = "Unknown";
				end

				local nHits = tonumber(DB.getValue(nodeRecord, "hits", 0)) or 0;
				if nHits <= 0 then
					nHits = tonumber(DB.getValue(nodeRecord, "hits.max", 0)) or 0;
				end

				local nLevel = tonumber(DB.getValue(nodeRecord, "level", 0)) or 0;
				local nBonus = nHits + (20 * nLevel);

				local nodeEntry = DB.createChild(nodeList);
				if not nodeEntry then
					return false;
				end

				local sCategory = "Dropped Entry";
				local sText = string.format("%s - (XP + %d)", sFoeName, nBonus);

				DB.setValue(nodeEntry, "order", "number", nOrder);
				DB.setValue(nodeEntry, "category", "string", sCategory);
				DB.setValue(nodeEntry, "bonus", "number", nBonus);
				DB.setValue(nodeEntry, "foe", "string", sFoeName);
				DB.setValue(nodeEntry, "text", "string", sText);

				return true;
			end



			function session2total()
				local tot;
				tot = sessiontotal.getValue() + totaltotal.getValue();
				totaltotal.setValue(tot);
				reset();
				refresh();
			end

			function total2xp()
				local tot;
				tot = xp.getValue() + totaltotal.getValue();
				xp.setValue(tot);
				totaltotal.setValue(0);

				-- Calcular e atualizar o nÃ­vel do personagem
				local nNewLevel = CalcLevelFromXP(tot);
				level.setValue(nNewLevel);

				-- Atualizar os bÃ´nus de nÃ­vel das skills
				local nodeChar = getDatabaseNode().getParent();
				if nodeChar and isHostOrOwner() then
					DB.setValue(nodeChar, "level", "number", nNewLevel);
				end
			end

			function getcombatxpdesc()
				local combatxpdesc;
				crittot = math.floor(combatxpdesc)
				return combatxpdesc;
			end

				function crit()
				local crittot = 0; -- Inicializa o total crï¿½tico
				local combatMultiplier = combatxpdesc.getValue() or 1; -- Multiplicador apenas para os valores afetados
				crittot = (norma.getValue() + (unca.getValue()* 0.1) + (downa.getValue()*0.2) + (stuna.getValue()*0.5) + (soloa.getValue()*2) + (largea.getValue()*1.5)+ (vlargea.getValue()*2)) * 5;
				crittot = crittot + ((normb.getValue() + (uncb.getValue()* 0.1) + (downb.getValue()*0.2) + (stunb.getValue()*0.5) + (solob.getValue()*2) + (largeb.getValue()*1.5)+ (vlargeb.getValue()*2)) * 10);
				crittot = crittot + ((normc.getValue() + (uncc.getValue()* 0.1) + (downc.getValue()*0.2) + (stunc.getValue()*0.5) + (soloc.getValue()*2) + (largec.getValue()*1.5)+ (vlargec.getValue()*2)) * 15);
				crittot = crittot + ((normd.getValue() + (uncd.getValue()* 0.1) + (downd.getValue()*0.2) + (stund.getValue()*0.5) + (solod.getValue()*2) + (larged.getValue()*1.5)+ (vlarged.getValue()*2)) * 20);
				crittot = crittot + ((norme.getValue() + (unce.getValue()* 0.1) + (downe.getValue()*0.2) + (stune.getValue()*0.5) + (soloe.getValue()*2) + (largee.getValue()*1.5)+ (vlargee.getValue()*2)) * 25);		
				   crittot = crittot + ((selfa.getValue() * 100) / combatMultiplier) + ((selfb.getValue() * 200) / combatMultiplier) + ((selfc.getValue() * 300) / combatMultiplier) + ((selfd.getValue() * 400) / combatMultiplier) + ((selfe.getValue() * 500) / combatMultiplier);
				crittot = math.floor(crittot)
				return crittot;
			end

			function reset()
				routine.setValue(0); easy.setValue(0); light.setValue(0); medium.setValue(0); hard.setValue(0); veryhard.setValue(0); extremelyhard.setValue(0); sheerfolly.setValue(0); absurd.setValue(0);
				hitsgiven.setValue(0); hitstaken.setValue(0); foekill.setValue(0); foekillbase.setValue(0); combatkills.setValue(0); 
				clearFoeKillBonusEntries();
				norma.setValue(0); selfa.setValue(0); unca.setValue(0); downa.setValue(0); stuna.setValue(0); soloa.setValue(0); largea.setValue(0); vlargea.setValue(0);
				normb.setValue(0); selfb.setValue(0); uncb.setValue(0); downb.setValue(0); stunb.setValue(0); solob.setValue(0); largeb.setValue(0); vlargeb.setValue(0);
				normc.setValue(0); selfc.setValue(0); uncc.setValue(0); downc.setValue(0); stunc.setValue(0); soloc.setValue(0); largec.setValue(0); vlargec.setValue(0);
				normd.setValue(0); selfd.setValue(0); uncd.setValue(0); downd.setValue(0); stund.setValue(0); solod.setValue(0); larged.setValue(0); vlarged.setValue(0);
				norme.setValue(0); selfe.setValue(0); unce.setValue(0); downe.setValue(0); stune.setValue(0); soloe.setValue(0); largee.setValue(0); vlargee.setValue(0);
				spellone.setValue(0); spelltwo.setValue(0); spellthree.setValue(0); spellfour.setValue(0); spellfive.setValue(0); spellsix.setValue(0); spellseven.setValue(0); spelleight.setValue(0); spellnine.setValue(0); spellten.setValue(0); spelleleven.setValue(0);
				ideaxp.setValue(0); trvlxp.setValue(0); trvl2xp.setValue(0); adventuretotal.setValue(0);
				refresh()
			end

number_boxed.script:
function onInit()
    if super and super.onInit then
        super.onInit();
    end
    if getValue() < 1 then
        setValue(1);
    end
end

function onValueChanged()
    if getValue() < 1 then
        setValue(1);
    end
    window.refresh();
end

buttoncontrol.script:
function onInit()
	if window.isHostOrOwner() then
		setVisible(true);
	else
		setVisible(false);
	end
end

function onButtonPress()
	window.session2total();
end

  function onInit()
	if window.isHostOrOwner() then
	  setVisible(true);
	else
	  setVisible(false);
	end
  end

  function onButtonPress()
	window.total2xp();
  end

number_boxed.script:

function onValueChanged()
	window.refresh();
end

function onInit()
	if super and super.onInit then
		super.onInit();
	end
	if getValue()==0 then
		setValue(1);
	end
	window.refresh();
end

combobox_labeled_RMC.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end

	setComboBoxReadOnly(true);
	window.refreshFoeKillBonusCombo();
end

function onDrop(x, y, draginfo)
	if draginfo.isType("shortcut") then
		local sClass, sRecord = draginfo.getShortcutData();
		if window.addFoeKillBonusEntryFromShortcut(sClass, sRecord) then
			window.refreshFoeKillBonusCombo();
			return true;
		end
	end

	return false;
end
